{
  "summary": "The paper proposes a novel, lightweight out-of-distribution (OOD) detection method for conditional language models (CLMs) based on Mahalanobis distance computed over input/output embeddings, outperforming perplexity and other baselines on summarization and translation tasks. By combining OOD scores with perplexity, the method enables selective generation that improves output quality under distribution shifts, supported by extensive experiments and human evaluations.",
  "strengths": [
    {
      "point": "Novel OOD detection approach using CLM embeddings and Mahalanobis distance",
      "evidence": "The method leverages input/output embeddings from encoder-decoder CLMs and fits Gaussian models to compute relative Mahalanobis distances, outperforming perplexity and other baselines in AUROC for OOD detection."
    },
    {
      "point": "Effective selective generation framework combining OOD scores with perplexity",
      "evidence": "Combining OOD scores with perplexity improves correlation with human and automatic quality metrics by up to 12% and enables abstention from low-quality outputs, as shown in Quality vs Abstention curves."
    },
    {
      "point": "Comprehensive evaluation including human ratings and multiple datasets",
      "evidence": "Experiments span summarization and translation tasks with near and far OOD datasets, supported by human quality assessments and multiple automatic metrics."
    }
  ],
  "weaknesses": [
    {
      "point": "Lack of comparison to established embedding-based OOD methods and adaptation details",
      "evidence": "The paper omits comparisons to standard baselines like energy-based detection, ODIN, and deep ensembles adapted for CLMs, weakening novelty claims."
    },
    {
      "point": "Insufficient methodological validation of Gaussian assumptions and embedding extraction choices",
      "evidence": "No quantitative goodness-of-fit tests for Gaussianity or ablations on embedding pooling strategies are provided, limiting confidence in modeling assumptions."
    },
    {
      "point": "Missing reproducibility details and potential data leakage concerns",
      "evidence": "Critical implementation details such as covariance estimation, embedding extraction pipeline, and dataset overlap analysis are absent, hindering replication and raising validity questions."
    },
    {
      "point": "Limited evaluation scope and missing uncertainty baselines",
      "evidence": "Experiments focus only on summarization and translation; strong uncertainty estimation baselines like MC dropout or ensembles are not included."
    },
    {
      "point": "Lack of statistical significance testing and calibration analysis",
      "evidence": "Quality vs Abstention curves lack confidence intervals or significance tests; calibration of OOD scores is not evaluated."
    }
  ],
  "questions": [
    {
      "question": "How do established embedding-based OOD detection methods adapted for CLMs compare to the proposed Mahalanobis distance approach?",
      "motivation": "Understanding comparative performance is critical to validate novelty and practical advantages."
    },
    {
      "question": "How robust is the Gaussian assumption on embeddings across different tasks and model architectures?",
      "motivation": "Validating modeling assumptions affects generalizability and effectiveness of the OOD detection method."
    },
    {
      "question": "What is the computational overhead of the proposed method compared to perplexity and other baselines in real-world deployment scenarios?",
      "motivation": "Practical applicability depends on efficiency and scalability."
    },
    {
      "question": "How does the method perform on other conditional generation tasks beyond summarization and translation, such as dialogue or code generation?",
      "motivation": "Demonstrating broader applicability strengthens impact claims."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
